def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    total_bins = len(bins)
    avg_capacity = np.mean(bins[bins > 0]) if np.any(bins > 0) else 1
    for i in range(total_bins):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1:
            score = 0.0
        elif ratio > 0.9:
            score = (1 - ratio) ** 4 + 0.15
        elif 0.7 < ratio <= 0.9:
            score = np.exp(-(ratio * 12)) + 0.12
        elif 0.4 < ratio <= 0.7:
            for k in range(1, 8):
                val = ((-1) ** (k+1)) * (ratio ** (k + 2)) / (k * 1.3)
                score += val
            score = abs(score) + 0.07
        else:
            temp_sum = 0.0
            for p in range(1, 10):
                temp_sum += ((-1) ** p) * (ratio ** (p + 1)) / (p * 1.7)
            score = abs(temp_sum) + 0.1
        neighbors_influence = 0.0
        neighbors_weights_sum = 0.0
        for offset in range(1, 7):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < total_bins:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff_ratio = abs(capacity - neighbor_capacity) / max(capacity, neighbor_capacity)
                    weight = 1 / (offset ** 1.5)
                    neighbors_influence += diff_ratio * weight * 0.1
                    neighbors_weights_sum += weight
        if neighbors_weights_sum > 0:
            neighbors_influence /= neighbors_weights_sum
        capacity_factor = (capacity ** 0.6) + (avg_capacity ** 0.4)
        if capacity_factor == 0:
            capacity_factor = 1
        if capacity < item * 1.1:
            penalty = (item - capacity) ** 2 * 0.5
        else:
            penalty = 0
        if i % 3 == 0:
            score *= 0.85
            neighbors_influence *= 1.1
        elif i % 5 == 0:
            score *= 1.05
            neighbors_influence *= 0.95
        priority = score + neighbors_influence / capacity_factor + penalty
        if priority < 0:
            priority = 0
        priorities[i] = priority
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_finite = np.max(finite_priorities)
    for i in range(total_bins):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 4.5
    return priorities
